// FIX Bug 6: The original workflow had no output step — users submitted the form
// and never received their tailored resume link. This node builds the response
// data that the Form Response node will display.

const docId = $('Build Formatting Requests').first().json.docId;
const fullName = $('Merge Resume Text + Job Description').first().json['full_name'];
const jobTitle = $('Merge Resume Text + Job Description').first().json['job_title'];
const docUrl = `https://docs.google.com/document/d/${docId}/edit`;

return [{
  json: {
    docId,
    docUrl,
    full_name: fullName,
    job_title: jobTitle,
    message: `Your tailored resume for the ${jobTitle} role is ready! Click the link below to view and download your Google Doc.`,
    resumeLink: docUrl
  }
}];

let html = $('Generate Tailored Resume').item.json.candidates[0].content.parts[0].text;

// Strip accidental markdown fences
html = html
  .replace(/```html/gi, '')
  .replace(/```/g, '')
  .trim();

const docId = $('Create Google Doc').item.json.id;
const requests = [];
let cursor = 1;

function stripTags(str) {
  return str
    .replace(/<strong[^>]*>(.*?)<\/strong>/gi, '$1')
    .replace(/<em[^>]*>(.*?)<\/em>/gi, '$1')
    .replace(/<b[^>]*>(.*?)<\/b>/gi, '$1')
    .replace(/<i[^>]*>(.*?)<\/i>/gi, '$1')
    .replace(/<a[^>]*>(.*?)<\/a>/gi, '$1')
    .replace(/<[^>]+>/g, '')
    .replace(/\*\*([^*]+)\*\*/g, '$1')
    .replace(/\*([^*]+)\*/g, '$1')
    .replace(/&amp;/g, '&')
    .replace(/&lt;/g, '<')
    .replace(/&gt;/g, '>')
    .replace(/&nbsp;/g, ' ')
    .replace(/&#39;/g, "'")
    .replace(/&quot;/g, '"')
    .trim();
}

function insertBlock(text, { paragraphStyle = {}, textStyle = {}, bullet = false } = {}) {
  const trimmed = text.replace(/\n/g, ' ').trim();
  if (!trimmed) return;

  const content = trimmed + '\n';
  const startIndex = cursor;
  const endIndex = cursor + content.length;

  requests.push({ insertText: { location: { index: cursor }, text: content } });

  if (Object.keys(paragraphStyle).length) {
    requests.push({
      updateParagraphStyle: {
        range: { startIndex, endIndex },
        paragraphStyle,
        fields: Object.keys(paragraphStyle).join(',')
      }
    });
  }

  if (Object.keys(textStyle).length) {
    requests.push({
      updateTextStyle: {
        range: { startIndex, endIndex },
        textStyle,
        fields: Object.keys(textStyle).join(',')
      }
    });
  }

  if (bullet) {
    requests.push({
      createParagraphBullets: {
        range: { startIndex, endIndex: endIndex - 1 },
        bulletPreset: 'BULLET_DISC_CIRCLE_SQUARE'
      }
    });
  }

  cursor = endIndex;
}

requests.push({
  updateDocumentStyle: {
    documentStyle: {
      marginTop:    { magnitude: 54, unit: 'PT' },
      marginBottom: { magnitude: 54, unit: 'PT' },
      marginLeft:   { magnitude: 54, unit: 'PT' },
      marginRight:  { magnitude: 54, unit: 'PT' }
    },
    fields: 'marginTop,marginBottom,marginLeft,marginRight'
  }
});

const tokenRegex = /<(h1|h2|h3|p|ul|ol)[^>]*>([\s\S]*?)<\/\1>/gi;
let match;

while ((match = tokenRegex.exec(html)) !== null) {
  const tag = match[1].toLowerCase();
  const inner = match[2];
  const text = stripTags(inner);

  if (tag === 'h1') {
    insertBlock(text, {
      paragraphStyle: {
        alignment: 'CENTER',
        spaceAbove: { magnitude: 0, unit: 'PT' },
        spaceBelow: { magnitude: 4, unit: 'PT' }
      },
      textStyle: {
        bold: true,
        fontSize: { magnitude: 24, unit: 'PT' },
        weightedFontFamily: { fontFamily: 'Calibri' },
        foregroundColor: { color: { rgbColor: { red: 0.1, green: 0.1, blue: 0.1 } } }
      }
    });

  } else if (tag === 'h2') {
    insertBlock(text, {
      paragraphStyle: {
        alignment: 'START',
        spaceAbove: { magnitude: 14, unit: 'PT' },
        spaceBelow: { magnitude: 3, unit: 'PT' }
      },
      textStyle: {
        bold: true,
        underline: true,
        fontSize: { magnitude: 11, unit: 'PT' },
        weightedFontFamily: { fontFamily: 'Calibri' },
        foregroundColor: { color: { rgbColor: { red: 0.18, green: 0.18, blue: 0.55 } } }
      }
    });

  } else if (tag === 'h3') {
    insertBlock(text, {
      paragraphStyle: {
        alignment: 'START',
        spaceAbove: { magnitude: 8, unit: 'PT' },
        spaceBelow: { magnitude: 2, unit: 'PT' }
      },
      textStyle: {
        bold: true,
        fontSize: { magnitude: 10.5, unit: 'PT' },
        weightedFontFamily: { fontFamily: 'Calibri' },
        foregroundColor: { color: { rgbColor: { red: 0.1, green: 0.1, blue: 0.1 } } }
      }
    });

  } else if (tag === 'p') {
    const isContact = /\|/.test(inner) && (/@/.test(inner) || /\+\d/.test(inner) || /linkedin/i.test(inner));
    insertBlock(text, {
      paragraphStyle: {
        alignment: isContact ? 'CENTER' : 'START',
        spaceAbove: { magnitude: 0, unit: 'PT' },
        spaceBelow: { magnitude: isContact ? 8 : 4, unit: 'PT' },
        lineSpacing: 115
      },
      textStyle: {
        fontSize: { magnitude: 10, unit: 'PT' },
        weightedFontFamily: { fontFamily: 'Calibri' },
        foregroundColor: { color: { rgbColor: { red: 0.2, green: 0.2, blue: 0.2 } } }
      }
    });

  } else if (tag === 'ul' || tag === 'ol') {
    const liRegex = /<li[^>]*>([\s\S]*?)<\/li>/gi;
    let liMatch;
    while ((liMatch = liRegex.exec(inner)) !== null) {
      const liText = stripTags(liMatch[1]);
      if (!liText) continue;
      insertBlock(liText, {
        paragraphStyle: {
          alignment: 'START',
          spaceAbove: { magnitude: 1, unit: 'PT' },
          spaceBelow: { magnitude: 1, unit: 'PT' },
          lineSpacing: 115,
          indentStart:     { magnitude: 18, unit: 'PT' },
          indentFirstLine: { magnitude: -18, unit: 'PT' }
        },
        textStyle: {
          fontSize: { magnitude: 10, unit: 'PT' },
          weightedFontFamily: { fontFamily: 'Calibri' },
          foregroundColor: { color: { rgbColor: { red: 0.2, green: 0.2, blue: 0.2 } } }
        },
        bullet: true
      });
    }
  }
}

return [{ json: { docId, requests } }];

// FIX Bug 3 & 4: extractFromFile outputs ONLY { text: '...' }, discarding
// job_description_text and all form fields. We re-merge here by pulling
// the full context from Pre-Extract Binary Check (which has everything)
// and attaching the extracted resume text from Extract Resume Text.

const fullItem = $('Pre-Extract Binary Check').first();
const extractedItem = $input.first();

const resumeText = (extractedItem.json.text ?? '').trim();

if (!resumeText) {
  throw new Error('Could not extract text from the uploaded PDF. Make sure the PDF is not scanned/image-only.');
}

return [{
  json: {
    ...fullItem.json,
    resume_text: resumeText
    // job_description_text, full_name, job_title etc. are preserved from fullItem.json
  },
  binary: fullItem.binary
}];

// FIX Bug 3: extractFromFile would replace the entire item and lose job_description_text.
// Instead we extract the PDF text ourselves via the binary data and merge everything
// into one item so Build Prompt has access to BOTH fields.
//
// n8n's extractFromFile node cannot be used here without data loss, so we hand the
// binary key name to the next node and let the built-in Extract node run, then
// we recombine with a Code node immediately after.
//
// Strategy: pass through the full merged item; the Extract node follows and we
// re-merge in the next Code node.

const item = $input.first();

// Ensure resume_pdf binary is present (defensive re-check after branch merge).
if (!item.binary || !item.binary.resume_pdf) {
  throw new Error('Missing resume PDF binary at extraction stage. Ensure the form upload is sending a file.');
}

return [item];

// FIX Bug 2: Set nodes drop binary. Use Code node to preserve binary
// while also setting the job_description_text field from the pasted value.

const formItem = $('Form: Resume Submission').first();
const jobDescriptionText = (formItem.json['job_description'] ?? '').trim();

return [{
  json: {
    ...formItem.json,
    job_description_text: jobDescriptionText
  },
  binary: formItem.binary
}];

// FIX Bug 1: Jina AI returns the scraped text in $json.data (responseFormat:'text'),
// NOT $json.body. Previous workflow mapped $json.body which was always undefined.
//
// FIX Bug 2: Set nodes silently drop binary data. Instead of using a Set node
// we use Code nodes on both branches so we can explicitly carry the binary forward.

const formItem = $('Form: Resume Submission').first();
const jinaItem = $input.first();

// $json.data is where n8n places the raw text body for responseFormat:'text'
const jobDescriptionText = (jinaItem.json.data ?? '').trim();

if (!jobDescriptionText) {
  throw new Error('Jina AI returned an empty response. The LinkedIn URL may be inaccessible or require login. Try pasting the job description directly.');
}

return [{
  json: {
    ...formItem.json,
    job_description_text: jobDescriptionText
  },
  binary: formItem.binary
}];

// FIX: Validate required inputs before proceeding.
// Ensures the user actually filled in whichever job-source field they chose.
const item = $input.first();
const inputType = item.json['input_type'] ?? '';
const jobDescription = (item.json['job_description'] ?? '').trim();
const linkedinUrl = (item.json['linkedin_url'] ?? '').trim();

if (inputType === 'LinkedIn job URL' && !linkedinUrl) {
  throw new Error('You selected "LinkedIn job URL" but did not provide a URL. Please go back and fill in the LinkedIn URL field.');
}

if (inputType === 'Paste job description' && !jobDescription) {
  throw new Error('You selected "Paste job description" but left it empty. Please go back and paste the job description.');
}

// Also normalise binary key so downstream nodes always find resume_pdf.
item.binary = item.binary ?? {};
if (!item.binary.resume_pdf) {
  const keys = Object.keys(item.binary);
  const resumeKey = keys.find(k => k === 'resume_pdf' || k.startsWith('resume_pdf'));
  if (resumeKey) {
    item.binary.resume_pdf = item.binary[resumeKey];
    if (resumeKey !== 'resume_pdf') delete item.binary[resumeKey];
  } else if (keys.length === 1) {
    const onlyKey = keys[0];
    item.binary.resume_pdf = item.binary[onlyKey];
    if (onlyKey !== 'resume_pdf') delete item.binary[onlyKey];
  }
}

if (!item.binary.resume_pdf) {
  throw new Error('No resume PDF found in the upload. Please resubmit with a valid PDF file.');
}

return [item];
